mapper.select:
/* ess 충방전량 조회 */ select site_id, std_timestamp, sum(chg_val) as chg_val, sum(dischg_val) as dischg_val from ( select ess_chg_idx, site_id, device_id, std_timestamp, std_date, chg_val, dischg_val, reg_date from tb_ess_charge where 1=1 and site_id = #{siteId }
and std_date between str_to_date(#{selTermFrom },'%Y%m%d%H%i%s') and str_to_date(#{selTermTo },'%Y%m%d%H%i%s')
and std_date between str_to_date(#{schTermFrom },'%Y%m%d%H%i%s') and str_to_date(#{schTermTo },'%Y%m%d%H%i%s')
) a where 1=1 group by site_id, std_timestamp order by std_timestamp

/* ess 예측 충방전량 조회 */ select site_id, std_timestamp, sum(chg_val) as chg_val, sum(dischg_val) as dischg_val from ( select ess_chg_plan_idx, site_id, device_id, std_timestamp, std_date, chg_val, dischg_val, reg_date, mod_date from tb_ess_charge_plan where 1=1 and site_id = #{siteId }
and std_date between str_to_date(#{selTermFrom },'%Y%m%d%H%i%s') and str_to_date(#{selTermTo },'%Y%m%d%H%i%s')
and std_date between str_to_date(#{schTermFrom },'%Y%m%d%H%i%s') and str_to_date(#{schTermTo },'%Y%m%d%H%i%s')
) a where 1=1 group by site_id, std_timestamp order by std_timestamp
